import sys

def get_max_weight(w, counts):
    max_weight = w
    if w == 0:
        return 0
    for i in range(1, 9):
        if counts[i] > 0:
            for j in range(i + 1, 9):
                if counts[j] > 0:
                    if i + j <= w:
                        max_weight = max(max_weight, i + j)
    return max_weight

def main():
    w = int(input())
    counts = list(map(int, input().split()))
    max_weight = get_max_weight(w, counts)
    print(max_weight)

if __name__ == "__main__":
    main()
